<section class="py-5"><div class="container" style="max-width:900px"><div class="card shadow-sm"><div class="card-body p-4 p-lg-5"><div class="text-center mb-4"><h1 class="h3"><?=e($agreement['title'])?></h1><div class="text-muted"><?=e($agreement['agreement_number'])?> · <?=e($agreement['display_name'])?></div></div><div class="border rounded p-4 bg-light" style="white-space:pre-wrap"><?=e($agreement['body'])?></div><?php if($agreement['status']!=='signed'):?><form method="post" action="/agreement/<?=e($token)?>/sign" class="mt-4"><?=csrf_field()?><div class="row g-3"><div class="col-md-6"><label class="form-label">Printed name</label><input name="signed_name" class="form-control" required></div><div class="col-md-6"><label class="form-label">Email</label><input type="email" name="signed_email" value="<?=e($agreement['email'])?>" class="form-control" required></div></div><input type="hidden" name="signature_data" id="signatureData"><div class="my-3"><label class="form-label">Signature</label><canvas id="signaturePad" class="border rounded w-100" height="180"></canvas><button type="button" id="clearSignature" class="btn btn-sm btn-link">Clear</button></div><button class="btn btn-primary">Sign Agreement</button></form><script>const c=document.getElementById('signaturePad'),x=c.getContext('2d');let d=false;function p(e){const r=c.getBoundingClientRect();return{x:(e.clientX-r.left)*(c.width/r.width),y:(e.clientY-r.top)*(c.height/r.height)}}c.addEventListener('pointerdown',e=>{d=true;const q=p(e);x.beginPath();x.moveTo(q.x,q.y)});c.addEventListener('pointermove',e=>{if(!d)return;const q=p(e);x.lineTo(q.x,q.y);x.stroke()});window.addEventListener('pointerup',()=>{d=false;document.getElementById('signatureData').value=c.toDataURL()});document.getElementById('clearSignature').onclick=()=>{x.clearRect(0,0,c.width,c.height);document.getElementById('signatureData').value=''}</script><?php else:?><div class="alert alert-success mt-4">Signed by <?=e($agreement['signed_name'])?> on <?=e($agreement['signed_at'])?>.</div><?php endif?></div></div></div></section>
